<?php

namespace Database\Seeders;

use App\Models\Activity;
use Illuminate\Database\Seeder;

/**
 * School tier activities — ages 6–12 years.
 * Subjects: math(80), literacy(65), science(65), technology(50),
 *           engineering(40), geography(40), history(40), coding(35),
 *           art(30), language(30), character(30), social(25),
 *           quran(50, Muslim only), islamic_studies(50, Muslim only), arabic(40, Muslim only)
 *
 * is_free: first 8 per subject = true, rest = false
 * age_min / age_max: integer years (6–12)
 * Muslim-gated subjects (quran, arabic, islamic_studies) are filtered at the
 * ChildProfile::appropriateActivities() model layer — no DB flag needed here.
 */
class SchoolActivitySeeder extends Seeder
{
    public function run(): void
    {
        foreach (array_chunk($this->activities(), 100) as $chunk) {
            foreach ($chunk as $data) {
                Activity::updateOrCreate(
                    ['title' => $data['title']],
                    array_merge($data, ['language' => 'en', 'like_count' => 0])
                );
            }
        }
    }

