            ['title' => 'Cybersecurity: Staying Safe Online', 'subject' => 'coding', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Identify common online threats (phishing, malware, weak passwords), evaluate password strength, and write 5 rules for staying safe online.', 'instructions' => '1. Define: phishing, malware, two-factor authentication.\n2. Evaluate 5 passwords for strength: "abc123", "P@ssword1!", a long passphrase.\n3. Write 5 personal cybersecurity rules.\n4. Apply: what does Islam say about honesty and trust — how does this apply to online behaviour?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify online threats and evaluate password strength', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'My First App: Design and Prototype', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 50, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design a paper prototype for a simple app (e.g. a Quran verse of the day app or a prayer time reminder), applying UI/UX thinking and user stories.', 'instructions' => '1. Write a user story: "As a Muslim, I want to see a verse of the day so I can remember Allah throughout my day."\n2. Sketch 3 screen wireframes.\n3. Label each UI element.\n4. Test with a family member: walk them through it and note 2 improvement points.', 'materials_needed' => 'Pencil, A4 paper, ruler', 'learning_objectives' => 'Create a paper prototype app with user stories and wireframes', 'age_group' => 'school', 'is_muslim_only' => false],


            // Coding 26-35
            ['title' => 'Data Science: Collecting, Cleaning, and Displaying Data', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Conduct a simple survey, enter results into a spreadsheet, clean the data, and produce a pie chart and bar chart comparing two categories.', 'instructions' => '1. Design a 4-question survey.\n2. Collect 10 responses.\n3. Enter and clean the data (remove blanks, fix typos).\n4. Create a pie chart for one question and a bar chart for another.', 'materials_needed' => 'Computer with spreadsheet, pencil for survey', 'learning_objectives' => 'Collect, clean, and visualise data in a spreadsheet', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Web Design: Accessibility and Inclusivity', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand web accessibility principles (alt text, contrast, keyboard navigation) and audit a simple webpage to identify and fix accessibility issues.', 'instructions' => '1. Define web accessibility and explain why it matters.\n2. List 4 accessibility features and how to implement them in HTML/CSS.\n3. Audit your HTML page from earlier: add alt text to images, check colour contrast.\n4. Link to Islamic values: how does accessibility reflect care for those with different needs?', 'materials_needed' => 'Computer with browser and HTML file', 'learning_objectives' => 'Identify and fix accessibility issues in a webpage', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'JavaScript: Adding Interactivity to a Web Page', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 45, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Add a basic JavaScript button click event to a web page that changes text content, introducing the concept of DOM manipulation.', 'instructions' => '1. Add a button to your HTML page.\n2. Add: <script> document.getElementById("myBtn").onclick = function() { document.getElementById("demo").innerHTML = "Clicked!"; } </script>\n3. Test the click event.\n4. Modify to toggle between two messages.', 'materials_needed' => 'Computer with text editor and browser', 'learning_objectives' => 'Add a JavaScript click event that manipulates the DOM', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Pseudocode and Flowcharts', 'subject' => 'coding', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write pseudocode and draw a flowchart for a program that checks if a number is prime, using standard flowchart shapes and pseudocode conventions.', 'instructions' => '1. Define pseudocode and describe when to use it.\n2. Write pseudocode for a prime number checker.\n3. Draw a flowchart for the same logic (use correct shapes: start/end oval, process rectangle, decision diamond).\n4. Trace through the flowchart for input = 7 and input = 9.', 'materials_needed' => 'Pencil, paper', 'learning_objectives' => 'Write pseudocode and draw a flowchart for a logic-based algorithm', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Databases: Tables, Records, and Queries', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand what a database is, create a simple flat-file database of 10 books, and write SELECT query statements using WHERE, ORDER BY, and basic filtering.', 'instructions' => '1. Create a table with fields: ID, Title, Author, Subject, Year.\n2. Add 10 rows of Islamic book data.\n3. Write 3 queries: SELECT * WHERE subject = "fiqh"; ORDER BY year DESC.\n4. Explain: why is a database better than a spreadsheet for 10,000 books?', 'materials_needed' => 'Pencil, paper or spreadsheet', 'learning_objectives' => 'Design a database table and write SELECT queries with filtering', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Version Control: What is Git?', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand why version control matters, and simulate a Git workflow (init, add, commit, branch, merge) using paper cards or a beginner online tool.', 'instructions' => '1. Define version control and give a real-world analogy ("tracked changes" in a document).\n2. Simulate: git init → git add → git commit with 3 paper code cards.\n3. Create a "branch" (another set of cards with a different change) and "merge".\n4. Explain: what is a merge conflict and how is it resolved?', 'materials_needed' => 'Pencil, paper cards', 'learning_objectives' => 'Explain version control and simulate the git workflow', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'App Ethics and Digital Responsibility', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Examine the ethics of software design: dark patterns, addictive design, data harvesting, and bias in algorithms — applying Islamic principles to evaluate each.', 'instructions' => '1. Define: dark pattern, attention economy, algorithmic bias.\n2. Give a real example of each.\n3. Apply: does the app respect the user\'s time and well-being?\n4. Design a "halal-first" technology principle: what 3 rules would guide an ethical Muslim software engineer?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify unethical design patterns and apply Islamic ethics to technology', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Open Source vs Proprietary Software', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Compare open source and proprietary software on cost, privacy, community, and security, and evaluate the Islamic principle of sharing knowledge freely.', 'instructions' => '1. Define open source and proprietary.\n2. List 3 examples of each type.\n3. Compare using 4 criteria: cost, security, privacy, customisation.\n4. How does open source reflect the Islamic tradition of sharing knowledge (ilm)?', 'materials_needed' => 'Pencil, comparison table template', 'learning_objectives' => 'Compare open source and proprietary software and link to Islamic values', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Computing and Careers: Where Coding Takes You', 'subject' => 'coding', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the wide range of careers that use programming skills — from game development and cybersecurity to Islamic fintech, medical tech, and AI for halal certification.', 'instructions' => '1. List 10 careers that use coding (beyond just "programmer").\n2. Choose one that could serve the Muslim community directly.\n3. Draw a career map: what skills and education would you need?\n4. Write a one-sentence vision: "In 10 years I want to code _____ because _____."\n', 'materials_needed' => 'Pencil, career map template', 'learning_objectives' => 'Connect coding skills to a range of careers including Muslim community needs', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Capstone: Build a Digital Islamic Resource', 'subject' => 'coding', 'age_min' => 10, 'age_max' => 12, 'duration_minutes' => 60, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Apply all learned skills to plan and build a mini digital Islamic resource — a Scratch quiz, Python dua generator, or simple HTML page — presenting it to a family member.', 'instructions' => '1. Choose a format: Scratch quiz, Python dua/adhkar tool, or HTML Islamic info page.\n2. Plan: write a brief spec (purpose, audience, features).\n3. Build. Debug. Test.\n4. Present to a family member and collect 2 pieces of feedback.', 'materials_needed' => 'Computer, choice of tool (Scratch / Python / HTML)', 'learning_objectives' => 'Plan, build, test, and present a complete digital Islamic resource project', 'age_group' => 'school', 'is_muslim_only' => false],

            // Art 1-15
            ['title' => 'Islamic Geometric Patterns: Introduction', 'subject' => 'art', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Explore the beauty and mathematical precision of Islamic geometric patterns. Draw a basic repeated tile pattern using a compass and ruler.', 'instructions' => '1. Explain: why did Islamic artists use geometry (no figurative art in places of worship)?\n2. Use a compass to draw a circle.\n3. Divide it into six equal parts.\n4. Connect the points to form a 6-pointed star tile and colour it.', 'materials_needed' => 'Compass, ruler, pencil, colour pencils', 'learning_objectives' => 'Construct a basic Islamic geometric tile pattern using compass and ruler', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Colour Theory: Primary, Secondary, Tertiary', 'subject' => 'art', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Mix primary colours to create secondary colours and identify tertiary colours on a hand-painted colour wheel.', 'instructions' => '1. Paint red, yellow, and blue in three segments of a circle.\n2. Mix pairs to create orange, green, and purple.\n3. Paint the secondary colours between the primaries.\n4. Identify and paint one tertiary colour pair.', 'materials_needed' => 'Paint (red, yellow, blue), paper, brush', 'learning_objectives' => 'Mix colours and construct a 6-part colour wheel', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Observational Drawing: Still Life', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 35, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Set up a simple still life (a fruit, a cup, a book) and practise observational drawing, focusing on accurate proportion, outline, and tone.', 'instructions' => '1. Arrange 3 objects and set up your paper and pencil.\n2. Sketch the outlines first — check proportions before adding detail.\n3. Add shading (hatching or blending) to show the light direction.\n4. Compare your drawing to the objects: what would you correct?', 'materials_needed' => 'Pencil, eraser, plain paper, 3 still life objects', 'learning_objectives' => 'Draw a still life with accurate proportion and tonal shading', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Arabic Calligraphy Basics: Naskh Style', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Introduce Arabic calligraphy through the Naskh style — the most readable script. Practise the basic letter forms and write "Bismillah" in guided calligraphy.', 'instructions' => '1. Look at examples of Naskh calligraphy.\n2. Practise the basic stroke (left to right descent).\n3. Trace the letters of Bismillah from a template.\n4. Write freehand with a calligraphy pen or thick marker.', 'materials_needed' => 'Calligraphy pen or thick marker, tracing paper, Naskh template', 'learning_objectives' => 'Write Bismillah in Naskh calligraphy style with guided practice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Watercolour Wash: Landscape Skies', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Learn the wet-on-wet and wet-on-dry watercolour techniques to paint a sunset or sunrise sky, reflecting on the sign of Allah in nature.', 'instructions' => '1. Wet the paper with clean water first.\n2. Drop in yellow, then orange, then a touch of purple at the top.\n3. Allow to bloom naturally.\n4. When dry, add a simple silhouette (mosque dome, tree) in black paint.', 'materials_needed' => 'Watercolour paint, brush, watercolour paper, water', 'learning_objectives' => 'Apply wet-on-wet technique to paint a watercolour landscape sky', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Perspective Drawing: One-Point Perspective', 'subject' => 'art', 'age_min' => 8, 'age_max' => 11, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Use one-point perspective to draw a corridor or road vanishing to a single point on the horizon, creating a convincing sense of depth.', 'instructions' => '1. Draw a horizontal line (horizon) across the middle of the paper.\n2. Mark a vanishing point in the centre.\n3. Draw a rectangle in the foreground and connect its corners to the VP.\n4. Add parallel lines for floor tiles or windows fading to the VP.', 'materials_needed' => 'Pencil, ruler, plain paper', 'learning_objectives' => 'Draw a one-point perspective scene with a single vanishing point', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Mosaic Art Inspired by Islamic Tilework', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Create a mosaic artwork inspired by the zellige tilework of Morocco and Al-Andalus, using cut paper pieces in geometric arrangements.', 'instructions' => '1. Look at photos of Moroccan mosaic tilework.\n2. Draw a geometric template (star shape or interlocking hexagons).\n3. Cut small paper squares and rectangles and glue within each section in a single colour.\n4. Leave thin white gaps between tiles to simulate grouting.', 'materials_needed' => 'Coloured paper, scissors, glue, pencil, template', 'learning_objectives' => 'Create a mosaic artwork inspired by Islamic zellige tilework', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Portrait Drawing: Proportions of the Face', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Learn the standard proportions of the human face (eyes at the midline, nose at ¾ line) and draw a front-facing portrait applying these guidelines.', 'instructions' => '1. Draw an oval for the head.\n2. Divide in half horizontally — place eyes on this line.\n3. Divide the lower half: nose at the lower quarter, mouth midway.\n4. Add ears aligned with eyes to nose. Draw hair and shade.', 'materials_needed' => 'Pencil, eraser, plain paper', 'learning_objectives' => 'Apply facial proportion guidelines to draw a front-facing portrait', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Printing: Lino or Foam Relief Printing', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 45, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Carve a simple geometric or floral design into foam sheet, apply ink, and make multiple print copies — exploring how Islamic artists used repetition in decoration.', 'instructions' => '1. Sketch a simple geometric or floral design on the foam.\n2. Carve or indent the design using a pencil or blunt tool.\n3. Apply ink/paint with a roller.\n4. Press onto paper 4 times to create a repeat pattern.', 'materials_needed' => 'Foam sheet, ink/paint, roller or brush, paper', 'learning_objectives' => 'Carve and print a repeated Islamic motif using relief printing', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Tonal Drawing: Light, Shadow, and Form', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a tonal scale from white to black in 5 grades, then apply tonal shading to a 3D sphere to show how light creates form.', 'instructions' => '1. Draw 5 squares in a row and shade from white (unshaded) to dark.\n2. Draw a circle.\n3. Identify the light source (top left) and shade the sphere: highlight, mid-tone, shadow, reflected light, cast shadow.\n4. Evaluate: does your sphere look 3D?', 'materials_needed' => 'Pencil (HB and 4B), plain paper', 'learning_objectives' => 'Apply tonal shading to make a 2D circle look like a 3D sphere', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Architecture Sketch: Islamic Buildings', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Look at images of iconic Islamic architecture (the Blue Mosque, Alhambra, Al-Masjid an-Nabawi) and sketch one using pencil, focusing on arches, domes, and minarets.', 'instructions' => '1. Study the building photograph for 1 minute.\n2. Sketch lightly the overall outline.\n3. Add architectural detail: horseshoe arches, muqarnas (honeycomb vaulting), tilework patterns.\n4. Annotate: label the key architectural features.', 'materials_needed' => 'Pencil, eraser, plain paper, building image reference', 'learning_objectives' => 'Sketch an iconic Islamic building identifying its key architectural features', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Mixed Media: Collage and Texture', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a nature-themed mixed media artwork combining collage, painting, and texture-rubbing, inspired by the quranic instruction to reflect on creation.', 'instructions' => '1. Create texture rubbings from leaves and bark on tracing paper.\n2. Tear and collage coloured paper for a background sky and ground.\n3. Glue texture rubbings as trees or ground.\n4. Paint a focal point (animal or plant) on top in watercolour.', 'materials_needed' => 'Coloured paper, watercolour, tracing paper, pencil, glue, leaves and bark', 'learning_objectives' => 'Produce a mixed media artwork combining collage, texture, and paint', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Zentangle: Mindful Pattern Drawing', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Fill a divided shape with repetitive fine-pen Zentangle patterns — a meditative drawing practice that mirrors the contemplative dimension of Islamic art.', 'instructions' => '1. Draw a simple outline shape (star, hand, name in calligraphic letters).\n2. Divide the inside with curved borders.\n3. Fill each section with a different repetitive Zentangle pattern (spirals, grid, petals).\n4. Reflect: how does careful, repetitive art-making feel? Connect to dhikr (remembrance).', 'materials_needed' => 'Fine black pen, plain white paper', 'learning_objectives' => 'Create a detailed Zentangle artwork using repetitive patterns', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Colour and Emotion: Expressive Painting', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore how artists use warm and cool colours to create emotional responses. Create two paintings of the same simple subject: one using only warm colours, one with only cool colours.', 'instructions' => '1. Explain: warm colours (red, orange, yellow) vs cool colours (blue, green, purple).\n2. Paint a simple bowl of fruit using only warm colours.\n3. Paint the same subject again using only cool colours.\n4. Compare: how does the emotional feel differ?', 'materials_needed' => 'Paint (full range), paper, brush', 'learning_objectives' => 'Demonstrate how warm and cool colours create different emotional responses', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Sculpture: Clay Pinch Pot with Islamic Decoration', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 45, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Form a small clay pinch pot and decorate the outside with an impressed or incised geometric Islamic pattern, exploring form, texture, and symmetry in 3D.', 'instructions' => '1. Take a ball of clay and press thumb into centre.\n2. Pinch and rotate to form an even pot.\n3. Smooth the walls.\n4. Press a geometric pattern (star, interlocking hexagons) into the outer surface using a pencil.', 'materials_needed' => 'Air-dry clay or modelling clay, pencil for patterning', 'learning_objectives' => 'Form a pinch pot and add Islamic geometric surface decoration', 'age_group' => 'school', 'is_muslim_only' => false],


            // Art 16-30
            ['title' => 'Film Poster Design: Typography and Composition', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design a halal animated film poster, applying design principles: rule of thirds, hierarchy, font choice, and limited colour palette.', 'instructions' => '1. Sketch 3 thumbnail layout options for the poster.\n2. Choose the best layout and develop it at A4 size.\n3. Apply rule of thirds: place focal image off-centre.\n4. Choose 2 complementary colours and design a bold title in a calligraphic or styled font.', 'materials_needed' => 'Pencil, colour pencils, A4 paper, ruler', 'learning_objectives' => 'Apply design principles (rule of thirds, hierarchy, colour) to a poster', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Abstract Art: Mondrian Grid Painting', 'subject' => 'art', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a Mondrian-inspired abstract composition using only horizontal and vertical black lines, filled with the three primaries and white/grey.', 'instructions' => '1. Draw a grid of horizontal and vertical black lines on white paper.\n2. Vary the size of rectangles.\n3. Fill: some rectangles in red, some yellow, some blue — leave others white.\n4. Discuss: what makes this artistic even without recognisable objects?', 'materials_needed' => 'Black marker, pencil, ruler, red/yellow/blue paint or pencil', 'learning_objectives' => 'Create an abstract Mondrian-style composition applying primary colours', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Nature Drawing: Botanical Illustration', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 45, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Draw a real plant or flower using detailed botanical illustration techniques: fine outline, hatching, and careful observation of vein patterns and symmetry.', 'instructions' => '1. Find a flower, leaf, or small plant.\n2. Draw the outline exactly as you see it — no guessing.\n3. Add vein details and shade using hatching.\n4. Label the parts: petal, sepal, stamen, leaf, stem.', 'materials_needed' => 'Fine pencil, plain paper, real plant subject', 'learning_objectives' => 'Create an accurate botanical illustration with labelled parts', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Op Art: Optical Illusion Drawing', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create an Op Art optical illusion by drawing concentric curved lines that create a 3D bulge or ripple effect using only black and white.', 'instructions' => '1. Draw a simple curved shape (circle or square) in the centre.\n2. Draw another slightly larger around it.\n3. Continue adding curves, bending them slightly at the centre to suggest the illusion.\n4. Fill alternate spaces black and white.', 'materials_needed' => 'Fine black pen, plain white paper, pencil', 'learning_objectives' => 'Construct an Op Art optical illusion using concentric curved lines', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Designing a Book Cover', 'subject' => 'art', 'age_min' => 8, 'age_max' => 11, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design a book cover for an Islamic story, applying visual hierarchy (title largest), an illustration that captures the theme, and a deliberate colour palette.', 'instructions' => '1. Choose an Islamic story (Uwais al-Qarni, Rabi\'ah al-Adawiyyah, or a Quranic story).\n2. Sketch 2 cover concepts.\n3. Develop the best concept in colour: include title, author name, and illustration.\n4. Evaluate: does the cover communicate the book\'s theme to a reader at a glance?', 'materials_needed' => 'Pencil, colour pencils, A4 paper', 'learning_objectives' => 'Design a communicative book cover applying visual hierarchy', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Photography Composition: The Rule of Thirds', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the rule of thirds, leading lines, and framing as photography composition techniques, then take 5 photos applying each principle.', 'instructions' => '1. Explain rule of thirds with a diagram.\n2. Draw a 9-square grid on a printed photo — identify where the subject sits.\n3. Take 5 photos using: rule of thirds, leading lines, framing, symmetry, or close-up.\n4. Annotate each: which principle? Does it work?', 'materials_needed' => 'Camera or phone camera, printed photos, pencil', 'learning_objectives' => 'Apply 3 composition principles in original photographs', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Batik-Inspired Fabric Art', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 50, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a batik-inspired artwork on cotton fabric using wax resist (candle or white crayon) and fabric dye or watered-down paint, referencing the rich batik traditions of Muslim cultures in Indonesia and West Africa.', 'instructions' => '1. Sketch a geometric or floral pattern on cotton with pencil.\n2. Draw over the lines firmly with a white crayon or candle (wax resist).\n3. Paint over the whole fabric with diluted fabric dye or paint.\n4. The wax areas will resist the colour, revealing the pattern.', 'materials_needed' => 'White cotton fabric, white crayon, fabric dye or paint, pencil, brush', 'learning_objectives' => 'Apply wax resist technique to produce a batik-inspired fabric pattern', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Architecture Inspired Art: Arches and Domes', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design an imaginary Islamic-inspired building using architectural drawing techniques, including horseshoe arches, arabesque patterns, and a central dome.', 'instructions' => '1. Sketch the front elevation of your building.\n2. Include at least two arch types (horseshoe, ogee, or pointed).\n3. Add a central dome with a crescent finial.\n4. Fill wall panels with geometric or arabesque pattern.', 'materials_needed' => 'Pencil, ruler, fine pen, colour pencils', 'learning_objectives' => 'Design an imaginary Islamic architectural building incorporating key features', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Illuminated Manuscript: Decorating a Letter', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Illuminate an Arabic or English letter in the style of Islamic Quranic manuscripts — using geometric and floral borders in gold, red, and blue.', 'instructions' => '1. Look at examples of Islamic manuscript illumination.\n2. Write a large letter (or Bismillah) in the centre of the paper.\n3. Surround it with a thin geometric border.\n4. Decorate the outer margin with interlocking arabesque leaf patterns in gold/yellow, red, and blue.', 'materials_needed' => 'Fine pen, gold/yellow, red, blue colour pencils or paint, plain paper', 'learning_objectives' => 'Create an illuminated letter in the style of Islamic manuscript art', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Stained Glass Effect: Tissue Paper Art', 'subject' => 'art', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 35, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a stained glass effect inspired by the mashrabiyya lattice windows of traditional Islamic architecture, using torn tissue paper on a backlit surface.', 'instructions' => '1. Draw a geometric grid pattern (large hexagons or stars) with pencil on white card.\n2. Trace over with black marker.\n3. Fill each section with torn pieces of coloured tissue paper glued with PVA.\n4. Hold to a window: observe the light effect.', 'materials_needed' => 'White card, coloured tissue paper, PVA glue, black marker', 'learning_objectives' => 'Create a light-transmitting stained glass effect using geometric patterns', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Monotype Printing: One-of-a-Kind Prints', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a monotype print (single unique print) by painting onto a glass surface and pressing paper on top, then enrich with drawing.', 'instructions' => '1. Apply paint to a flat surface (glass or plastic tray).\n2. Quickly press a sheet of paper on top and lift.\n3. Observe the unique texture and pattern.\n4. Draw into the print with pencil or fine pen to add detail.', 'materials_needed' => 'Paint, flat glass or tray, paper, pencil', 'learning_objectives' => 'Produce a unique monotype print and develop it with drawing', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Recycled Art: Making Something Beautiful from Waste', 'subject' => 'art', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 45, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a sculptural artwork from recycled packaging materials, applying the Islamic principle of avoiding waste and reflecting on beauty in creativity.', 'instructions' => '1. Collect boxes, tubes, lids, and packaging.\n2. Plan a sculpture: animal, building, or abstract form.\n3. Construct using tape and glue.\n4. Paint or decorate. Reflect: how does this activity connect to the principle of not wasting (la israf)?', 'materials_needed' => 'Recycled packaging, tape, glue, paint', 'learning_objectives' => 'Construct a sculpture from recycled materials and reflect on its Islamic ethic', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Art Analysis: Talking About Art', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Practise formal art analysis using the DESCRIBE, ANALYSE, INTERPRET, EVALUATE (DAIE) framework applied to a famous Islamic or world artwork.', 'instructions' => '1. Choose an artwork: a calligraphy panel, an Islamic tile pattern, or a portrait.\n2. DESCRIBE: what do you see (colour, line, shape, form, texture)?\n3. ANALYSE: how are the elements arranged? What technique?\n4. INTERPRET: what message or feeling does it communicate?\n5. EVALUATE: is it successful? Why?', 'materials_needed' => 'Artwork image printout, pencil, paper', 'learning_objectives' => 'Apply the DAIE framework to formally analyse an artwork', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Typography: Designing with Letters', 'subject' => 'art', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design an expressive word-image where the style and decoration of the lettering reflects the meaning — applying typography as a visual art form.', 'instructions' => '1. Choose a word: PEACE, LIGHT, PATIENCE, or an Arabic word.\n2. Draw the large block letters in pencil.\n3. Decorate each letter to visually represent its meaning (e.g. LIGHT filled with sun rays).\n4. Add colour and outline in fine pen.', 'materials_needed' => 'Pencil, fine pen, colour pencils, plain paper', 'learning_objectives' => 'Design expressive typography that communicates meaning through visual style', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'My Art Portfolio Page', 'subject' => 'art', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Select your favourite artwork from the term and present it on an annotated portfolio page: explaining inspiration, technique, elements used, what worked, and what you would change.', 'instructions' => '1. Choose your best piece of artwork.\n2. Glue or draw it onto a layout page.\n3. Annotate: inspiration, media and techniques, elements of art used.\n4. Evaluate: one strength and one thing to improve in your next piece.', 'materials_needed' => 'A3 paper, glue, colour pencils, pencil', 'learning_objectives' => 'Present and annotate artwork in a reflective portfolio page', 'age_group' => 'school', 'is_muslim_only' => false],

            // Character 1-10
            ['title' => 'What is Good Character? Understanding Akhlaq', 'subject' => 'character', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Introduce the concept of akhlaq (character and manners in Islam) and connect it to the Prophet\'s famous saying: "I was sent to perfect good character."', 'instructions' => '1. Explain: what is akhlaq?\n2. List 5 good character traits in Arabic and English (sidq, amanah, hilm, karam, sabr).\n3. Give a real example of each trait from your week.\n4. Draw yourself showing one of these traits.', 'materials_needed' => 'Pencil, plain paper', 'learning_objectives' => 'Name 5 Islamic character traits and give real-life examples of each', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Honesty and Truthfulness (Sidq)', 'subject' => 'character', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Explore the Islamic virtue of sidq (truthfulness) through the story of the Prophet ﷺ being known as Al-Amin, and practise recognising honest vs dishonest choices.', 'instructions' => '1. Explain: what is sidq and why is it important?\n2. Narrate: why was the Prophet ﷺ called Al-Amin before prophethood?\n3. Role-play 3 scenarios: what is the honest choice in each?\n4. Write 3 commitments to be more honest this week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain sidq and demonstrate honest decision-making in scenarios', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Kindness and Compassion (Rahmah)', 'subject' => 'character', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Explore the Islamic virtue of rahmah (mercy and compassion) through Hadith about kindness to animals, relatives, and strangers.', 'instructions' => '1. Explain rahmah with the hadith: "Those who are merciful will receive mercy from the Most Merciful."\n2. Read: the story of the Prophet ﷺ and the kitten.\n3. Brainstorm 5 acts of kindness you can do at home, school, and outdoors.\n4. Commit to one act of kindness today.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain rahmah and identify practical acts of kindness', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Patience (Sabr): Accepting What We Cannot Change', 'subject' => 'character', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Explore sabr (patience) as one of the greatest virtues in Islam — patience with difficulty, with people, and with delaying desires for greater good.', 'instructions' => '1. Define sabr: patience in hardship, patience from sin, patience in worship.\n2. Tell the story of the Prophet Ayyub (Job) as an example of sabr.\n3. Identify a situation in your life that requires sabr.\n4. Write a dua for sabr in English and its Arabic original.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Define three types of sabr and apply it to a personal situation', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Gratitude (Shukr): Counting Blessings', 'subject' => 'character', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Develop the practice of shukr (gratitude) by identifying and reflecting on the blessings of Allah in daily life and understanding that gratitude increases blessings.', 'instructions' => '1. Explain: "If you are grateful, I will give you more" (Quran 14:7).\n2. Write a gratitude list: 10 blessings big and small.\n3. Make a gratitude map: body, family, home, nature, faith.\n4. Write a personal thank-you letter to Allah in your own words.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify blessings and express gratitude through a personal letter', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Responsibility and Trustworthiness (Amanah)', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Understand amanah (trustworthiness and fulfilling responsibilities) as a quality valued in Islam — as a family member, student, community member, and steward of the earth.', 'instructions' => '1. Define amanah with an example from hadith.\n2. List your responsibilities at home, in school, and to the environment.\n3. Evaluate: are you fulfilling these amanat? Give yourself a score.\n4. Set one goal to improve your amanah this week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify personal responsibilities and set a goal to fulfil amanah', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Forgiveness and Letting Go', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Discuss why forgiveness (afw and safh) is a sign of strength in Islam, using the story of the Prophet\'s ﷺ forgiveness of the people of Makkah.', 'instructions' => '1. Explain: what is the difference between afw (pardon) and safh (turning away)?\n2. Narrate: the opening of Makkah — how did the Prophet respond to his enemies?\n3. Discuss: how does holding a grudge affect the person holding it?\n4. Write about one situation where you could choose to forgive.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain Islamic forgiveness and apply it to a personal situation', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Generosity (Karam) and Giving', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Explore karam (generosity) as a quality of Allah that Muslims are called to embody, through the stories of the companions who gave their last food to a guest.', 'instructions' => '1. Explain: "The generous person is close to Allah, close to people, and close to paradise." (Tirmidhi)\n2. Read the story of the Ansar who gave their food to a guest (Quran 59:9).\n3. Brainstorm 5 ways to be generous without money (time, attention, help, knowledge, smile).\n4. Do one generous act today and note how it made you feel.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify forms of generosity beyond money and practise one', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Respecting Parents and Elders', 'subject' => 'character', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand why respecting parents (birr al-walidayn) is one of the most important duties in Islam and identify practical ways to honour parents and elders in daily life.', 'instructions' => '1. Explain: the Quran commands respect for parents right after worship of Allah (17:23-24).\n2. List 5 ways to show respect to parents.\n3. List 3 ways to respect elders outside the home.\n4. Write a letter to a parent or grandparent expressing appreciation.', 'materials_needed' => 'Pencil, notebook, writing paper', 'learning_objectives' => 'Name Islamic duties to parents and express appreciation through writing', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Dealing with Anger: Islamic Strategies', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the Prophet\'s ﷺ advice about controlling anger and practise 3 strategies: saying A\'udhu billah, sitting down, and performing wudu.', 'instructions' => '1. Discuss: "The strong person is not the one who overcomes others; rather it is the one who controls himself when angry." (Bukhari)\n2. Name the 3 strategies from hadith.\n3. Role-play: something makes you angry — demonstrate each strategy.\n4. Write a personal pledge about anger management.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Recall 3 hadith-based strategies for managing anger and practise them', 'age_group' => 'school', 'is_muslim_only' => false],


            // Character 11-30
            ['title' => 'Courage and Standing for What is Right', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore Islamic courage (shajaa\'ah) not just as physical bravery but as the courage to speak truth, stand against injustice, and fear only Allah.', 'instructions' => '1. Define: what is true courage in Islam?\n2. Discuss: "Whoever sees an evil, let him change it with his hand; if he cannot, then with his tongue; if he cannot, then with his heart." (Muslim)\n3. Identify a scenario where courage is needed. Role-play the right response.\n4. Write about a time you showed moral courage.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain Islamic courage and identify opportunities to apply it', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Self-Discipline: Habits and Daily Routine', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Design a personal daily routine that balances worship, learning, family, rest, and health — applying the prophetic principle that the best deeds are the most regular, even if small.', 'instructions' => '1. Discuss: "The most beloved deeds to Allah are the most regular, even if they are small." (Bukhari)\n2. Design a daily schedule: Fajr through Isha with activity in between.\n3. Identify: where are the gaps? How can they be filled with beneficial habits?\n4. Commit to one new small daily habit this week.', 'materials_needed' => 'Pencil, daily schedule template', 'learning_objectives' => 'Design a balanced daily routine based on Islamic priorities', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Empathy: Seeing from Another\'s Point of View', 'subject' => 'character', 'age_min' => 8, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Practise empathy — understanding others\' feelings and perspectives — through role-playing scenarios and the hadith "None of you truly believes until he loves for his brother what he loves for himself."', 'instructions' => '1. Discuss the hadith on loving for your brother what you love for yourself.\n2. Read 3 scenario cards and describe how the other person might feel.\n3. Role-play: one person shares a problem, the other listens and responds with empathy.\n4. Reflect: when was the last time you truly listened to someone?', 'materials_needed' => 'Scenario cards, pencil', 'learning_objectives' => 'Demonstrate empathy by identifying others\' feelings in scenarios', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Gratitude Journal: 30-Day Practice', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 15, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Start a 30-day gratitude journal practice, writing 3 things you are grateful for each day, linking to the Quranic promise that gratitude brings more blessings.', 'instructions' => '1. Set up a notebook as your gratitude journal.\n2. Write today\'s date and 3 things you are grateful for — be specific.\n3. Continue for 30 days.\n4. After 1 week: review — have your entries changed? Are you noticing more blessings?', 'materials_needed' => 'Notebook, pencil', 'learning_objectives' => 'Begin a consistent gratitude journaling practice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Conflict Resolution: Solving Problems Peacefully', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the 4-step Islamic conflict resolution process: cool down, listen, express calmly, find a solution — practised through role-play of common conflicts.', 'instructions' => '1. Explain the 4 steps.\n2. Role-play: a conflict about sharing equipment — apply all 4 steps.\n3. Discuss: what role does sulh (reconciliation) play in Islam?\n4. Write a personal conflict resolution commitment.', 'materials_needed' => 'Pencil, conflict scenario cards', 'learning_objectives' => 'Apply a 4-step Islamic conflict resolution process in practice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Growth Mindset: I Cannot Do It YET', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the power of a growth mindset — the belief that abilities grow with effort — and connect it to the Islamic tawakkul (trust in Allah combined with action).', 'instructions' => '1. Explain fixed vs growth mindset with examples.\n2. Replace fixed statements ("I can\'t do maths") with growth ones ("I can\'t do this YET — but with practice I will").\n3. Connect: tawakkul = trust in Allah AND taking action.\n4. Write 3 growth mindset challenges for the week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Reframe fixed mindset statements into growth mindset statements', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Sincerity (Ikhlas): Doing Things for the Right Reason', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore ikhlas (sincerity of intention) and riya (showing off) — understanding why Islam places intention at the heart of every action.', 'instructions' => '1. Explain: "Actions are by intentions." (Bukhari)\n2. Describe riya: what is showing off and why is it harmful?\n3. Role-play 3 situations: identify if the intention is ikhlas or riya.\n4. Before your next action, silently make your niyyah (intention) for the sake of Allah.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Distinguish ikhlas from riya and practise setting a sincere intention', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'The Character of the Prophet ﷺ', 'subject' => 'character', 'age_min' => 7, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Study 10 character traits of the Prophet Muhammad ﷺ as described in authentic Hadith, and choose one to embody this week.', 'instructions' => '1. Read about 10 traits of the Prophet ﷺ : gentleness, generosity, humility, justice, patience, truthfulness, courage, simplicity, smile, concern for others.\n2. For each, find a hadith or story.\n3. Choose your "character focus" for this week.\n4. Write how you will demonstrate that trait and report back in a week.', 'materials_needed' => 'Pencil, notebook, hadith reference', 'learning_objectives' => 'Identify 10 prophetic character traits and commit to practising one', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Respect for Differences', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand that Allah created people of different nations, colours, and languages as a sign, and that diversity is a gift — applying this to respectful engagement with others.', 'instructions' => '1. Read: "We created you from male and female and made you peoples and tribes that you may know one another." (49:13)\n2. Discuss: what does Islam say about racism and tribalism?\n3. List 5 ways people are different beyond race: personality, ability, interests, experiences.\n4. Role-play: how do you respond respectfully to someone very different from you?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Apply the Quranic principle of diversity and demonstrate respectful engagement', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Digital Character: Being Good Online', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Apply Islamic character traits (sidq, amanah, kindness) to online behaviour — identifying what it means to be a person of good character in digital spaces.', 'instructions' => '1. Discuss: why does your online behaviour reflect your character just as much as offline?\n2. List 5 ways Islamic character applies online (honesty in posts, not spreading unverified news, treating others kindly).\n3. Scenario: someone sends you false news — what is the Islamic response?\n4. Write your personal digital character pledge.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Apply Islamic character principles to digital behaviour', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Humility (Tawadu) vs Arrogance (Kibr)', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Contrast Islamic humility (tawadu) with arrogance (kibr), understanding why Islam considers kibr the most dangerous character flaw.', 'instructions' => '1. Define tawadu and kibr with examples.\n2. Discuss: "He who has even a mustard seed of kibr in his heart will not enter Jannah." (Muslim) — what does this teach us?\n3. Identify a situation where you might feel superior — how does tawadu guide you?\n4. List 3 practices that build humility.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Distinguish tawadu from kibr and identify humility-building practices', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Service to Others: Khidmah', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the Islamic value of khidmah (service to others) and plan a simple community service project that can be completed at home, school, or in the local community.', 'instructions' => '1. Define khidmah with the hadith: "The best of people are those who are most beneficial to people." (Al-Bayhaqi)\n2. Brainstorm 5 service projects of different scales.\n3. Plan one project: who needs help, what will you do, when, and what do you need?\n4. Complete the project and reflect: how did giving help make you feel?', 'materials_needed' => 'Pencil, project planning template', 'learning_objectives' => 'Plan and complete a simple service project based on the value of khidmah', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Taking Care of the Body: A Gift from Allah', 'subject' => 'character', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand that the body is an amanah from Allah and caring for it (sleep, nutrition, exercise) is an Islamic obligation, not just health advice.', 'instructions' => '1. Explain: your body is a trust given to you by Allah.\n2. List: 5 ways Islam encourages physical care (sleep, halal food, cleanliness, exercise, no self-harm).\n3. Assess your own habits: score 1–5 for each area.\n4. Set one habit goal for this week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify Islamic duties toward physical health and set a personal goal', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Managing Peer Pressure', 'subject' => 'character', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Identify peer pressure situations and practise assertive refusal strategies grounded in Islamic identity, using the prophetic model of choosing righteous companions.', 'instructions' => '1. Define peer pressure and give 3 examples a school child might face.\n2. Discuss: "A person is on the religion of his closest friend; so let each one of you look at who you take as a close friend." (Abu Dawud)\n3. Role-play: friend pressures you to watch haram content — give 3 response strategies.\n4. Identify 3 qualities of a righteous friend you should look for.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify peer pressure and practise assertive, values-based refusal strategies', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Identity: Who Am I as a Muslim?', 'subject' => 'character', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the multiple layers of identity (Muslim, family, national, cultural) and develop a confident, positive Islamic identity that embraces complexity.', 'instructions' => '1. Draw concentric circles: self at centre, then family, community, ummah, humanity.\n2. Write labels: what does being Muslim mean in each circle of your life?\n3. Discussion: can you be proud of your faith and proud of your nationality at the same time?\n4. Write a 3-sentence "I am" statement about your identity.', 'materials_needed' => 'Pencil, plain paper', 'learning_objectives' => 'Articulate a layered, positive Muslim identity in a personal statement', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Justice and Standing Against Oppression', 'subject' => 'character', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Study the Islamic principle of adl (justice) and understand that standing against oppression — even against one\'s own family — is an obligation for a Muslim.', 'instructions' => '1. Explain adl and zulm (oppression) from the Quran and Hadith.\n2. Discuss: "Help your brother whether he is an oppressor or oppressed." Explain the full meaning (to stop him from oppressing).\n3. Identify 3 forms of injustice in daily life.\n4. What is one action a young person can take against injustice?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Define adl and identify how a young Muslim can practise justice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'My Character Development Plan', 'subject' => 'character', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Synthesise your character learning into a personal 4-week development plan: target trait, daily practice, accountability partner, and weekly review.', 'instructions' => '1. Reflect on all character topics studied.\n2. Choose one virtue to work on for 4 weeks.\n3. Design a plan: daily action (5 minutes), weekly check-in, accountability partner.\n4. Write a letter to your future self describing the character you want to have.', 'materials_needed' => 'Pencil, character plan template', 'learning_objectives' => 'Create a 4-week personal character development plan', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Kindness Challenge: Random Acts of Good', 'subject' => 'character', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Complete a 7-day kindness challenge using a card of 7 different acts of kindness, recording the impact on the people around you and on yourself.', 'instructions' => '1. Draw a 7-day kindness card: write one different act for each day.\n2. Day 1: give a compliment to a sibling or parent.\n3. Each day: complete the act, then write 2 sentences about how it went.\n4. At the end of 7 days: what changed in your home atmosphere?', 'materials_needed' => 'Pencil, kindness card template', 'learning_objectives' => 'Complete 7 acts of kindness and reflect on their impact', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Reflection and Self-Accountability (Muhasabah)', 'subject' => 'character', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the Islamic practice of muhasabah (daily self-examination) and develop a personal evening reflection routine to grow in character.', 'instructions' => '1. Explain muhasabah: the practice of calling yourself to account before Allah calls you.\n2. Design a 5-minute evening routine: 3 things I did well, 1 thing I want to improve.\n3. Write today\'s muhasabah.\n4. Make a commitment to practise this each evening for one week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Develop and begin a daily muhasabah self-reflection practice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Manners at the Table (Adab at-Taam)', 'subject' => 'character', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn 10 prophetic table manners (adab at-taam) during mealtimes and role-play applying them during a family meal.', 'instructions' => '1. List 10 prophetic eating manners: Bismillah, right hand, not blowing on food, not criticising food, eating from nearest part, expressing gratitude.\n2. Role-play a family meal applying each manner.\n3. Discuss: how do table manners express respect for Allah\'s provision?\n4. Report: did you apply all 10 at your next real meal?', 'materials_needed' => 'Pencil, checklist card', 'learning_objectives' => 'Identify and apply 10 prophetic table manners', 'age_group' => 'school', 'is_muslim_only' => false],

            // Social 1-5
            ['title' => 'What is a Community? My Place in It', 'subject' => 'social', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Understand the concept of community and the different communities a child belongs to (family, mosque, school, neighbourhood, ummah), and the responsibility each brings.', 'instructions' => '1. Define community.\n2. List the 5 communities you belong to.\n3. For each: what do you contribute? What do you receive?\n4. Draw a community map with yourself in the centre.', 'materials_needed' => 'Pencil, plain paper', 'learning_objectives' => 'Identify personal communities and describe reciprocal responsibilities', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Teamwork and Cooperation', 'subject' => 'social', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Understand why teamwork is valued in Islam (Muslims are like one body) and practise a cooperative task that can only be completed by working together.', 'instructions' => '1. Discuss: "The Muslims are like one body: if one part hurts, the whole body responds." (Bukhari)\n2. Cooperative task: build the tallest tower with 20 blocks — no single hands allowed, all members must hold at some point.\n3. Reflect: what made it work? What caused problems?\n4. List 3 values a good team member needs.', 'materials_needed' => 'Building blocks or craft sticks', 'learning_objectives' => 'Demonstrate teamwork in a practical task and identify team values', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Communication Skills: Listening and Speaking', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Practise active listening and structured speaking using the P-E-E-L format, connecting to the Islamic emphasis on thoughtful, measured speech.', 'instructions' => '1. Explain active listening: eye contact, no interrupting, nodding, paraphrasing.\n2. Partner: one person speaks for 60 seconds, the other paraphrases back.\n3. Switch roles.\n4. Discuss: "Whoever believes in Allah and the Last Day, let him say something good or remain silent." — how does this apply to conversation?', 'materials_needed' => 'Timer', 'learning_objectives' => 'Demonstrate active listening and paraphrasing in partner communication', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Understanding Emotions', 'subject' => 'social', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Name and understand a wide range of emotions beyond happy/sad, connecting each to an Islamic response (gratitude for joy, sabr for sadness, A\'udhu billah for fear).', 'instructions' => '1. Create an emotion wheel: name 12 emotions.\n2. For each: what does your body feel? What is the Islamic guided response?\n3. Role-play 3 emotion scenarios.\n4. Discuss: is it OK to feel negative emotions? What matters is how we respond.', 'materials_needed' => 'Pencil, plain paper', 'learning_objectives' => 'Name 12 emotions and identify Islamic responses to each', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Friendship: Choosing and Being a True Friend', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Understand the Islamic concept of walaa (loyalty) and the hadith on companions, and identify the qualities of a good friend that Islam encourages.', 'instructions' => '1. Discuss: "A person is on the religion of his close friend." (Abu Dawud) — what does this mean for choosing friends?\n2. List 5 qualities of a good friend (honest, encouraging, helps you be better, keeps secrets appropriately, reliable).\n3. Self-assess: are you this kind of friend?\n4. Write a "friendship pledge" — what kind of friend will you be?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify qualities of a true Islamic friendship and commit to practising them', 'age_group' => 'school', 'is_muslim_only' => false],


            // Social 6-25
            ['title' => 'Bullying: What It Is and How to Stop It', 'subject' => 'social', 'age_min' => 7, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Define bullying (physical, verbal, cyber), understand why Islam condemns all forms of mockery and harm, and learn strategies for stopping bullying.', 'instructions' => '1. Define: physical, verbal, cyber, and relational bullying.\n2. Quran: "O believers, do not let one group mock another." (49:11) — how does this apply?\n3. Scenario: you see a classmate being excluded — what do you do? (bystander, upstander, ally)\n4. Design a 3-step anti-bullying commitment.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify types of bullying and describe the role of an upstander', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Leadership and Responsibility', 'subject' => 'social', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Understand the Islamic model of leadership (servant leadership, amana) and the hadith that every person is a shepherd responsible for their flock.', 'instructions' => '1. Discuss: "Every one of you is a shepherd and every one of you is responsible for his flock." (Bukhari)\n2. List 3 areas where you already have leadership (younger siblings, your own study, household chores).\n3. What makes a good leader: list 5 Islamic leadership qualities.\n4. Design a 1-week micro-leadership challenge.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify Islamic leadership principles and apply them in a personal challenge', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Manners with Guests and Hospitality', 'subject' => 'social', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Learn Islamic hospitality etiquette (karam ad-dayf): greeting guests, offering food and drink, giving the guest the best seat, and honouring them as a sunnah.', 'instructions' => '1. Explain: "Whoever believes in Allah and the Last Day should honour their guest." (Bukhari)\n2. List 7 Islamic manners with guests.\n3. Role-play: a guest arrives at your home — demonstrate all 7 manners.\n4. Discuss: what if you have guests and you don\'t want to share your room?', 'materials_needed' => 'None required', 'learning_objectives' => 'Demonstrate 7 Islamic hospitality manners in a role-play', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Dealing with Loss and Grief', 'subject' => 'social', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the Islamic framework for grief: it is natural and permitted; the prayer for loss (Inna lillahi wa inna ilayhi raji\'un) and the promise of reunion in Jannah.', 'instructions' => '1. Discuss: loss of a pet, friend moving away, or loss of a family member — how do you feel?\n2. Islam permits grief: "The eyes shed tears and the heart is grieved." (Bukhari)\n3. The dua of loss and its meaning: "Truly, to Allah we belong and truly to Him we return."\n4. Write a letter to someone you miss.', 'materials_needed' => 'Pencil, notebook, tissues available', 'learning_objectives' => 'Apply the Islamic framework of grief and use the inna-lillahi dua in context', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Community Helpers: Roles and Responsibilities', 'subject' => 'social', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the roles of different community helpers (doctor, teacher, imam, grocer, parent) and connect each to the Islamic concept of fard kifayah (collective duty).', 'instructions' => '1. Define fard kifayah: duties that the community must fulfil collectively.\n2. Name 8 community helper roles.\n3. Match each to a collective duty: if nobody did this job, what would happen?\n4. What would you like to contribute to your community when you grow up?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain fard kifayah and connect community roles to collective duty', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Masjid Etiquette and Community Worship', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the adab (etiquette) of visiting and worshipping at the masjid — entering, dress, silence, rows, respect — and the benefits of congregational prayer.', 'instructions' => '1. List 10 masjid etiquette rules.\n2. Discuss: the reward of congregational prayer is 27 times that of praying alone — what does this teach us about community?\n3. Role-play: family visit to the masjid — apply all 10 rules.\n4. Discuss: what responsibilities do you have as a member of your local masjid community?', 'materials_needed' => 'None required', 'learning_objectives' => 'Apply 10 masjid etiquette rules and explain the benefit of congregational worship', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Volunteering and Civic Participation', 'subject' => 'social', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Plan and deliver a small volunteer contribution to the community (family, school, masjid, or neighbourhood) applying the principle that even a smile is sadaqah.', 'instructions' => '1. Explore: what volunteer opportunities exist in your community?\n2. Choose one: help a neighbour, organise food for a charity, assist at the masjid, clean a communal space.\n3. Plan the activity: what, where, when, with whom.\n4. Deliver and reflect: what did you feel? What did others say?', 'materials_needed' => 'Depends on chosen project', 'learning_objectives' => 'Plan and complete a volunteer contribution and reflect on its impact', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Understanding Rules and Why We Need Them', 'subject' => 'social', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand why rules exist in families, schools, mosques, and societies, linking to the Quranic concept of sharia (a path) and the purpose of Islamic guidelines.', 'instructions' => '1. If there were no rules, what would happen? (brainstorm)\n2. List 5 rules from different contexts: home, school, masjid, road, games.\n3. For each: what is its purpose? Who does it protect?\n4. Connect: Islamic rules also have purposes — they protect life, family, mind, wealth, and honour.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain the purpose of rules in different social contexts', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Working Through Disagreements at Home', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Practise navigating common family disagreements (over screen time, siblings, chores) using respectful communication, forgiveness, and seeking common ground.', 'instructions' => '1. Name 3 common family disagreements.\n2. For each: what is the worst way to respond? What is the best?\n3. Role-play: sibling disagreement — demonstrate the Islamic way: calm, direct, forgive.\n4. Write: "When I disagree with family, I will..."', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Apply respectful communication strategies in family disagreement scenarios', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Islamic View on Money and Wealth', 'subject' => 'social', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand that money is a trust (amanah) from Allah, to be earned halal, spent wisely, and shared generously; introduce concepts of zakat and sadaqah as social bonds.', 'instructions' => '1. Explore: what does Islam say about earning, spending, and giving money?\n2. Define: halal income, haram income, israf (wasteful spending), zakat, sadaqah.\n3. Scenario: you receive Eid money (£30) — how would you distribute it Islamically?\n4. Write a personal "money values" statement.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Apply Islamic principles of earning, spending, and giving to a practical scenario', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Respecting Elders and Learning from the Elderly', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the Islamic honour given to the elderly and practise an intergenerational interview to capture family stories and wisdom.', 'instructions' => '1. Discuss: "Revering an old Muslim is part of revering Allah." (Abu Dawud)\n2. Write 5 interview questions to ask a grandparent or elderly neighbour.\n3. Conduct the interview and record 5 things learned.\n4. Reflect: what wisdom can young people gain from older generations?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Conduct an intergenerational interview and identify Islamic duties toward the elderly', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Social Media Literacy: Fact vs Opinion vs Fake News', 'subject' => 'social', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Develop critical social media literacy: distinguish fact from opinion, identify manipulation techniques, and apply the Quranic command to verify news before sharing.', 'instructions' => '1. Explain: fact, opinion, misinformation, disinformation.\n2. Quran: "O believers, if a wicked person brings you news, investigate, lest you harm people unknowingly." (49:6)\n3. Evaluate 3 sample social media posts: fact-check each.\n4. Create a personal "stop and check" habit before sharing any news.', 'materials_needed' => 'Pencil, sample post printouts', 'learning_objectives' => 'Apply fact-checking techniques and the Quranic verification principle to social media', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Environmental Responsibility: Khalifah on Earth', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the Islamic teaching that humans are Khalifah (stewards) of the Earth — responsible for protecting creation and not causing wasteful damage.', 'instructions' => '1. Explain khalifah and the prohibition of fasad (corruption on the Earth).\n2. List 5 ways your family can reduce environmental impact.\n3. Calculate: how much water is wasted per wudu if you leave the tap running for 3 minutes at 6L/min?\n4. Commit to 1 environmental change this week.', 'materials_needed' => 'Pencil, notebook, calculator', 'learning_objectives' => 'Explain the Islamic concept of khalifah and propose practical environmental actions', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Gender Respect and Islamic Adab', 'subject' => 'social', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand Islamic guidance on respectful interaction between genders, the meaning of hayaa (modesty), and why these guidelines protect dignity for everyone.', 'instructions' => '1. Discuss: what does Islam say about respectful interaction between boys and girls?\n2. Explain hayaa as protecting the dignity of others AND yourself.\n3. Scenario: appropriate vs inappropriate behaviours — categorise 10 examples.\n4. Discuss: Islam\'s approach is protective, not restrictive — why?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Explain hayaa and categorise appropriate vs inappropriate gender interaction', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Celebrating Diversity in the Ummah', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the beautiful diversity of the Muslim Ummah — different languages, cultures, food, clothing, and traditions — all united by one faith.', 'instructions' => '1. Map: how many countries have Muslim populations over 50%?\n2. Research: 3 different cultural traditions of Eid celebration.\n3. Discuss: which traditions are from Islam and which are from culture? How do we tell the difference?\n4. Create a "Diversity of the Ummah" poster.', 'materials_needed' => 'Pencil, coloured markers, paper', 'learning_objectives' => 'Distinguish Islamic practice from cultural tradition and celebrate Ummah diversity', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Safety Awareness: Protecting Yourself', 'subject' => 'social', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn personal safety rules for real-world and online situations — including body autonomy, safe adults, and when and how to ask for help.', 'instructions' => '1. Define safe adults: 5 people you trust completely.\n2. Body safety rules (private body parts, no one should touch without consent or medical need).\n3. Online safety: never share personal information, always tell a trusted adult about anything uncomfortable.\n4. Practice: role-play how to say NO and tell a safe adult.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify 5 safe adults and apply personal safety rules in scenarios', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Healthy Habits for the Mind (Mental Wellness)', 'subject' => 'social', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand mental wellness — recognise signs of anxiety and stress, and build a personal mental health toolkit using Islamic practices (dhikr, dua, exercise, social connection).', 'instructions' => '1. Explain stress and anxiety — they are normal and manageable.\n2. List 6 signs of stress in the body. (tight chest, headache, irritability, difficulty sleeping, etc)\n3. Build your mental health toolkit: dhikr, wudu, physical exercise, talking to a trusted adult, creative expression, sleep.\n4. When should you ask a grown-up for help?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify stress signs and build a personal Islamic mental wellness toolkit', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Social Responsibility: What Do I Owe the World?', 'subject' => 'social', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore the Islamic concept of social responsibility and how a Muslim\'s obligations extend beyond family to neighbours, community, the ummah, and humanity.', 'instructions' => '1. Discuss: "He is not a believer who goes to sleep full while his neighbour goes hungry." (Tabarani)\n2. Map ripples of responsibility: self, family, neighbours, community, ummah, humanity.\n3. For each level: what is one action you can take this month?\n4. Write a personal social responsibility commitment.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Identify social responsibilities at each level of community and commit to one action per level', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Cultural Traditions and Islamic Identity', 'subject' => 'social', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Navigate the relationship between cultural background and Islamic identity — celebrating halal cultural traditions while understanding which override and which are matters of choice.', 'instructions' => '1. List 3 cultural traditions in your family.\n2. For each: is it required by Islam, permitted, or contrary to Islamic teaching?\n3. Discuss: when culture conflicts with Islamic teaching, what takes priority?\n4. Celebrate one positive cultural tradition with your family this week.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Evaluate cultural traditions against Islamic principles and identify positive cultural heritage', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'My Rights and Responsibilities as a Citizen', 'subject' => 'social', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the rights and responsibilities of citizenship in a democratic society and the Islamic duty to be a beneficial, law-abiding member of the place you live.', 'instructions' => '1. List 5 rights you have as a child (education, safety, healthcare, play, family).\n2. For each right: what is the matching responsibility?\n3. Islam: Muslims must follow just laws of the land they live in — why?\n4. What is one civic responsibility you can act on right now (even as a child)?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Match civic rights to responsibilities and identify one personal civic duty', 'age_group' => 'school', 'is_muslim_only' => false],


            // Language 1-25
            ['title' => 'Parts of Speech: Nouns, Verbs, Adjectives', 'subject' => 'language', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Identify and sort nouns, verbs, and adjectives in sentences using colour-coding, building vocabulary through an Islamic story passage.', 'instructions' => '1. Define noun (person/place/thing), verb (action/state), adjective (describes noun).\n2. Colour-code a passage: nouns in blue, verbs in red, adjectives in green.\n3. Write 5 original sentences using at least 2 parts of speech each.\n4. Challenge: find a sentence with noun + adjective + verb and explain each word\'s job.', 'materials_needed' => 'Coloured pencils, passage printout', 'learning_objectives' => 'Identify nouns, verbs, and adjectives in a text and compose original sentences', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Reading Comprehension: Main Idea and Details', 'subject' => 'language', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Practise identifying the main idea and supporting details in a non-fiction passage, using a paragraph about a Muslim scientist or explorer.', 'instructions' => '1. Read a 2-paragraph passage.\n2. Ask: what is the main idea of each paragraph? Write one sentence for each.\n3. Find 3 supporting details per paragraph.\n4. Write a 2-sentence summary of the whole passage.', 'materials_needed' => 'Passage printout, pencil', 'learning_objectives' => 'Identify main idea and supporting details in an informational passage', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Writing a Paragraph: Topic Sentence to Conclusion', 'subject' => 'language', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Write a structured paragraph using the 4-part model: topic sentence, 2 supporting details, example, and conclusion — on a topic related to daily Islamic life.', 'instructions' => '1. Explain the 4-part paragraph structure.\n2. Model: write a paragraph together about "Why I pray."\n3. Student writes their own paragraph: topic could be "My favourite Islamic story" or "What Ramadan means to me."\n4. Peer share and give one compliment and one suggestion.', 'materials_needed' => 'Pencil, notebook, paragraph frame template', 'learning_objectives' => 'Write a structured 4-part paragraph independently', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Vocabulary Building: Context Clues', 'subject' => 'language', 'age_min' => 8, 'age_max' => 11, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Use context clues to decode unfamiliar vocabulary in a passage, applying 3 context clue strategies: definition, example, and inference.', 'instructions' => '1. Explain 3 context clue strategies.\n2. Read a passage with 5 bold vocabulary words.\n3. For each: circle context clues, make a definition guess, then check with a dictionary.\n4. Write each word in a new sentence of your own.', 'materials_needed' => 'Passage printout, dictionary, pencil', 'learning_objectives' => 'Use context clues to determine the meaning of unfamiliar vocabulary', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Punctuation: Full Stops, Commas, Question Marks', 'subject' => 'language', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Master the three most common punctuation marks through rewriting an unpunctuated passage, understanding how punctuation shapes meaning.', 'instructions' => '1. Explain rules for full stop, comma (in lists, after clauses), question mark, exclamation mark.\n2. Rewrite an unpunctuated paragraph with correct punctuation.\n3. Write 3 sentences of each type: statement, question, exclamation.\n4. Discuss: how does punctuation change the meaning of "Let\'s eat Grandma" vs "Let\'s eat, Grandma"?', 'materials_needed' => 'Pencil, notebook, passage printout', 'learning_objectives' => 'Apply correct punctuation in a rewriting exercise', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Persuasive Writing: Making an Argument', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Write a short persuasive paragraph using the OREO model (Opinion, Reason, Example, Opinion restate) on a child-relevant topic.', 'instructions' => '1. Explain OREO: Opinion – Reason – Example – Opinion.\n2. Model: "School should start later — here is why."\n3. Student chooses their own topic and writes an OREO paragraph.\n4. Share and evaluate: was the argument convincing? Why or why not?', 'materials_needed' => 'Pencil, notebook, OREO frame', 'learning_objectives' => 'Write a persuasive paragraph using the OREO model', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Story Writing: Beginning, Middle, End', 'subject' => 'language', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 35, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Write a complete short story with a clear beginning (setting + character), middle (problem), and end (resolution) — based on a moral from an Islamic story.', 'instructions' => '1. Explain story structure: beginning, middle, end.\n2. Choice of starter: story of Ibrahim\'s childhood or Bilal\'s courage or a fictional Muslim child character.\n3. Plan using a story map (beginning box, middle box, end box).\n4. Write the story (150–250 words), read aloud, and get feedback.', 'materials_needed' => 'Pencil, notebook, story map template', 'learning_objectives' => 'Compose a complete short story with narrative structure', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Spelling Strategies: Look, Cover, Write, Check', 'subject' => 'language', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => true, 'thumbnail_url' => null, 'description' => 'Practise the Look, Cover, Write, Check spelling strategy with a list of 20 commonly misspelled words sourced from Islamic and general English contexts.', 'instructions' => '1. Explain LCWC: look carefully at the word, cover it, write from memory, check against original.\n2. Work through 20 target words using LCWC.\n3. Any misspelled: repeat LCWC 3 more times.\n4. Write each correctly spelled word in a sentence.', 'materials_needed' => 'Pencil, spelling word list, notebook', 'learning_objectives' => 'Correctly spell 20 target words using the LCWC strategy', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Descriptive Writing: Using the 5 Senses', 'subject' => 'language', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write a vivid descriptive paragraph of a sensory-rich Islamic scene (Eid market, Madinah at Fajr, a busy masjid) using sight, sound, smell, taste, and touch.', 'instructions' => '1. Draw a 5-senses brainstorm table (see, hear, smell, taste, feel).\n2. Fill it for your chosen scene: Eid market or Masjid at Fajr or any vivid scene.\n3. Write a descriptive paragraph using at least one detail from each sense.\n4. Peer read: which sense description was most vivid?', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Write a sensory-rich descriptive paragraph using all 5 senses', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Reading Aloud with Expression', 'subject' => 'language', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Practise reading aloud with expression: pacing, emphasis, pausing at punctuation, and changing voice for different characters.', 'instructions' => '1. Explain the 4 elements: pace, volume, pause, expression.\n2. Read a passage flat (no expression) — how did it feel?\n3. Re-read with full expression: pause at full stops, louder for exclamations, questioning tone for questions.\n4. Record on a device if possible and listen back — give yourself one target.', 'materials_needed' => 'Book or passage, optional recording device', 'learning_objectives' => 'Read aloud with appropriate pace, volume, pause, and expression', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Non-Fiction Text Features: Contents, Index, Glossary', 'subject' => 'language', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Identify and use the key features of a non-fiction book: table of contents, index, glossary, headings, captions, and diagrams.', 'instructions' => '1. Label and explain each feature using an example book.\n2. Scavenger hunt: find a glossary definition, locate a topic using the index, find a captioned diagram.\n3. Write 5 of your own glossary definitions for vocabulary you\'ve learned this week.\n4. Create a mini contents page for a book you would write.', 'materials_needed' => 'Non-fiction book, pencil, notebook', 'learning_objectives' => 'Navigate non-fiction text features to locate information efficiently', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Poetry: Rhyme, Rhythm, and Free Verse', 'subject' => 'language', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Explore rhyming poetry and free verse, appreciating the Quran\'s literary beauty as the highest form of Arabic expression, and write one poem of each type.', 'instructions' => '1. Read examples of rhyming and free verse poetry.\n2. Identify: rhyme scheme (AABB, ABAB), meter (stressed/unstressed syllables).\n3. Write a 4-line rhyming poem about a season or celebration.\n4. Write a 4-line free verse poem about something that makes you feel grateful.', 'materials_needed' => 'Pencil, notebook, sample poems', 'learning_objectives' => 'Write both a rhyming poem and a free verse poem', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Report Writing: Researching and Presenting Facts', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 40, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write a structured report (introduction, subheadings, facts, conclusion) on a topic from the natural world or history, applying research skills.', 'instructions' => '1. Choose a topic: a biome, an animal, a historical figure.\n2. Plan: introduction (what is it?), 3 body sections with subheadings, conclusion (why it matters).\n3. Research using 2 sources — write notes, not copy.\n4. Write the report (200–300 words) and add one diagram or illustration.', 'materials_needed' => 'Pencil, notebook, reference books or approved websites', 'learning_objectives' => 'Write a structured factual report with subheadings and referenced information', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Prefixes and Suffixes for Vocabulary Growth', 'subject' => 'language', 'age_min' => 8, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn 10 common prefixes (un-, re-, pre-, dis-) and 10 suffixes (-ful, -less, -tion, -ing) and use them to decode and build new vocabulary.', 'instructions' => '1. List 10 prefixes with meanings and examples.\n2. List 10 suffixes with meanings and examples.\n3. Build 20 new words using prefix + root or root + suffix.\n4. Write 10 sentences using your new words.', 'materials_needed' => 'Pencil, word card set', 'learning_objectives' => 'Build and decode vocabulary using common English prefixes and suffixes', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Debate Skills: Arguing Both Sides', 'subject' => 'language', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'hard', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Practise structured debate: present arguments FOR and AGAINST a motion, developing the ability to see multiple perspectives and speak clearly in formal language.', 'instructions' => '1. Motion: "Homework should be banned" — prepare 3 arguments for AND 3 against.\n2. One side presents for 2 minutes; the other responds for 2 minutes.\n3. Switch sides and repeat.\n4. Reflect: which argument was hardest to make? Why is seeing both sides important?', 'materials_needed' => 'Pencil, argument plan cards', 'learning_objectives' => 'Construct and present formal arguments from two opposing positions', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Letter Writing: Formal and Informal', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the difference between formal and informal letters, practise both formats, and write a real letter to a friend or a formal letter to a charity requesting information.', 'instructions' => '1. Identify 5 differences between formal and informal letters.\n2. Write an informal letter to a friend about your best Eid memory.\n3. Write a formal letter to an Islamic charity asking how you can help.\n4. Compare: vocabulary, tone, structure of both letters.', 'materials_needed' => 'Pencil, notebook, letter format guide', 'learning_objectives' => 'Write both a formal and informal letter in correct format', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Similes and Metaphors in Creative Writing', 'subject' => 'language', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand and create similes (like/as) and metaphors, and use them to improve descriptive writing — with examples from Arabic literature and English poetry.', 'instructions' => '1. Define simile vs metaphor with examples.\n2. Arabic reference: the Quran uses vivid imagery (e.g., "He is like darkness in a deep ocean") — explore one example.\n3. Rewrite 5 dull sentences by adding a simile or metaphor.\n4. Write a 6-line descriptive paragraph using at least 3 similes or metaphors.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Write original similes and metaphors and apply them in descriptive writing', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Comprehension: Inference and Deduction', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Develop inference skills — reading between the lines — by answering questions that require reasoning beyond the literal text of a short story.', 'instructions' => '1. Explain: literal questions have answers in the text; inference questions require you to reason from clues.\n2. Read a short story.\n3. Answer 5 literal and 5 inference questions, marking which type each is.\n4. For inference answers: write the text evidence that helped you deduce the answer.', 'materials_needed' => 'Passage printout, pencil', 'learning_objectives' => 'Distinguish literal from inferential questions and provide text-evidence-based answers', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Book Review: Summarise and Recommend', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write a structured book review (title, author, genre, summary, opinion, recommendation) for a recently read book, developing critical reading habits.', 'instructions' => '1. Explain the structure: title/author, genre, what it\'s about (no spoilers!), did you enjoy it and why, would you recommend it?\n2. Write the review (150 words) for a favourite book.\n3. Star rating out of 5 with justification.\n4. Share with family: would anyone else read it based on your review?', 'materials_needed' => 'Pencil, notebook, recently read book', 'learning_objectives' => 'Write a structured book review with justified opinion and recommendation', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Grammar: Sentences, Clauses, and Phrases', 'subject' => 'language', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Understand the difference between a sentence, a main clause, a subordinate clause, and a phrase — and build compound and complex sentences.', 'instructions' => '1. Define: simple, compound, complex sentences.\n2. Identify: main clause vs subordinate clause in 5 examples.\n3. Expand 5 simple sentences into compound sentences using coordinating conjunctions (and, but, or, so).\n4. Expand 5 more into complex sentences using subordinating conjunctions (although, because, when, while).', 'materials_needed' => 'Pencil, notebook, conjunction word cards', 'learning_objectives' => 'Write compound and complex sentences using appropriate conjunctions', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Oral Presentation: Show and Tell', 'subject' => 'language', 'age_min' => 6, 'age_max' => 10, 'duration_minutes' => 30, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Prepare and deliver a 2-minute oral presentation about a personal object of significance — practising eye contact, clear voice, and audience engagement.', 'instructions' => '1. Choose an object that is meaningful to you (a book, a prayer mat, a gift).\n2. Plan: what is it? How did you get it? Why is it meaningful to you? What would you like others to know?\n3. Practise at least once alone.\n4. Deliver to family/group: maintain eye contact, speak clearly, engage the audience with a question.', 'materials_needed' => 'Chosen object', 'learning_objectives' => 'Deliver a structured 2-minute oral presentation with eye contact and clear voice', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Writing Instructions: How to Do Something', 'subject' => 'language', 'age_min' => 7, 'age_max' => 10, 'duration_minutes' => 25, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write clear, numbered instructions for a simple activity (how to make wudu, how to plant a seed, how to make a sandwich) using imperative verbs and time connectives.', 'instructions' => '1. Explain features of instructions: numbered steps, imperative verbs (pour, mix, place), time connectives (first, then, next, finally).\n2. Write instructions for "how to make wudu" — 8 steps minimum.\n3. Exchange with a partner: could they follow your instructions exactly without asking questions?\n4. Rewrite any unclear steps.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Write numbered instructions using imperative verbs and time connectives', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Reading Aloud: Building Fluency', 'subject' => 'language', 'age_min' => 6, 'age_max' => 9, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Build reading fluency through timed repeated reading — tracking words per minute (WPM) over three readings of the same passage, aiming for improvement each time.', 'instructions' => '1. Explain reading fluency: speed + accuracy + expression = fluency.\n2. Read a 100-word passage — time how long it takes.\n3. Calculate WPM: (words ÷ seconds) × 60.\n4. Re-read twice: does WPM improve? Does expression improve?\n5. Set a WPM target for next session.', 'materials_needed' => 'Passage, timer, notebook', 'learning_objectives' => 'Track and improve reading fluency in WPM across three readings', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'The Writing Process: Plan, Draft, Revise, Publish', 'subject' => 'language', 'age_min' => 8, 'age_max' => 12, 'duration_minutes' => 45, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Apply the full 4-stage writing process (plan, draft, revise, publish) to produce a polished 1-page piece on any topic of personal significance.', 'instructions' => '1. Stage 1 (Plan): brainstorm topic, audience, and structure (5 minutes).\n2. Stage 2 (Draft): write without stopping to edit — get ideas down (15 minutes).\n3. Stage 3 (Revise): re-read and improve word choice, sentence variety, structure (10 minutes).\n4. Stage 4 (Publish): write or type the final polished version neatly.', 'materials_needed' => 'Pencil, notebook, or word processor', 'learning_objectives' => 'Complete all 4 stages of the writing process to produce a polished piece', 'age_group' => 'school', 'is_muslim_only' => false],


            // Language 26-30
            ['title' => 'Digital Writing: Emails and Messages', 'subject' => 'language', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 25, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Learn the conventions of professional email and digital communication, applying Islamic adab (courtesy and care with words) to formal digital writing.', 'instructions' => '1. Explain email parts: subject line, salutation, body, sign-off.\n2. Compare: professional email vs casual text message — differences in language and tone.\n3. Write a formal email to a teacher explaining a missed assignment.\n4. Write an informal message to a friend about a weekend plan.\n5. Review: which needs more care with language and why?', 'materials_needed' => 'Pencil, notebook or device', 'learning_objectives' => 'Write a correctly formatted formal email and an appropriate informal message', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Newspaper Article: The 5 Ws', 'subject' => 'language', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 35, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Write a structured newspaper article answering the 5 Ws (Who, What, Where, When, Why) with a headline, byline, lead paragraph, and body using quotes.', 'instructions' => '1. Explain newspaper structure: headline, byline, lead, body, quote.\n2. Cover an imaginary (or real) event: a school science fair, or a fictional discovery.\n3. Answer all 5 Ws in the lead paragraph.\n4. Add one "quote" from a witness.\n5. Write a headline that would make someone want to read on.', 'materials_needed' => 'Pencil, notebook', 'learning_objectives' => 'Write a newspaper article using the 5 Ws model with a compelling headline', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Storytelling Through Comics', 'subject' => 'language', 'age_min' => 7, 'age_max' => 11, 'duration_minutes' => 35, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Create a 6-panel comic strip that tells a complete story with a beginning, middle, and end — combining visual art storytelling with written dialogue.', 'instructions' => '1. Explain comic conventions: speech bubbles, thought bubbles, action words, panel sequence.\n2. Plan your 6 panels: panels 1–2 = beginning, 3–4 = middle/problem, 5–6 = climax/resolution.\n3. Sketch (stick figures are fine!) and add speech/thought bubbles.\n4. Write a 2-sentence narrator introduction for the story.', 'materials_needed' => 'Pencil, blank comic template (6 panels), coloured pencils', 'learning_objectives' => 'Create a 6-panel comic strip with complete narrative structure and dialogue', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Public Speaking: Overcoming Fear', 'subject' => 'language', 'age_min' => 9, 'age_max' => 12, 'duration_minutes' => 30, 'difficulty' => 'medium', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Build confidence for public speaking through preparation, practice, and the Islamic perspective that speaking the truth clearly is a virtue — with structured speech delivery techniques.', 'instructions' => '1. Discuss: it is normal to feel nervous. What does the body do when nervous?\n2. Techniques: deep breath, slow down, steady eye contact, use gestures, pause for emphasis.\n3. Prepare a 60-second speech on "why I love learning."\n4. Deliver to family. Self-assess: which technique helped most?', 'materials_needed' => 'Prepared speech notes', 'learning_objectives' => 'Deliver a 60-second speech using at least 3 public speaking techniques', 'age_group' => 'school', 'is_muslim_only' => false],
            ['title' => 'Reading for Pleasure: Building a Book Habit', 'subject' => 'language', 'age_min' => 6, 'age_max' => 12, 'duration_minutes' => 20, 'difficulty' => 'easy', 'is_free' => false, 'thumbnail_url' => null, 'description' => 'Develop a personal reading habit — choosing books, tracking reading, and sharing books through a reading journal linked to the Islamic love of knowledge (seeking knowledge is an obligation).', 'instructions' => '1. Discuss: "Seek knowledge from the cradle to the grave."\n2. Set up a reading log: title, author, pages, dates, rating.\n3. Choose your next book from an approved list.\n4. Commit to 10 minutes of reading daily and log for 2 weeks.\n5. At the end: what was your favourite passage and why?', 'materials_needed' => 'Notebook, pencil, selected book', 'learning_objectives' => 'Establish a daily reading habit and maintain a 2-week reading log', 'age_group' => 'school', 'is_muslim_only' => false],

